SELECT ,
FROM users u LEFT JOIN user_roles ur ON ur.user_id = u.id LEFT JOIN roles r ON r.id = ur.role_id AND r.status = 1
AND ( u.email LIKE CONCAT('%', #{queryDTO.keyword}, '%') OR u.username LIKE CONCAT('%', #{queryDTO.keyword}, '%') OR u.nickname LIKE CONCAT('%', #{queryDTO.keyword}, '%') )
AND u.status = #{queryDTO.status}
AND EXISTS ( SELECT 1 FROM user_roles ur2 INNER JOIN roles r2 ON r2.id = ur2.role_id WHERE ur2.user_id = u.id AND r2.role_code = #{queryDTO.roleCode} AND r2.status = 1 )
AND u.created_at >= #{queryDTO.createdStart}
AND u.created_at <= #{queryDTO.createdEnd}
GROUP BY u.id, u.email, u.username, u.nickname, u.avatar_url, u.bio, u.status, u.created_at, u.updated_at ORDER BY u.created_at DESC, u.id DESC

SELECT u.id, u.nickname, u.email, u.avatar_url FROM users u
AND ( u.email LIKE CONCAT('%', #{queryDTO.keyword}, '%') OR u.username LIKE CONCAT('%', #{queryDTO.keyword}, '%') )
ORDER BY u.created_at DESC, u.id DESC LIMIT #{queryDTO.pageSize}

SELECT
    (
        SELECT COUNT(1)
        FROM travel_diaries td
        WHERE td.user_id = #{userId}
    ) AS diaryCount,
    (
        SELECT COUNT(1)
        FROM diary_comments dc
        WHERE dc.user_id = #{userId}
    ) AS commentCount,
    (
        SELECT COUNT(1)
        FROM uploaded_files uf
        WHERE uf.user_id = #{userId}
    ) AS uploadCount
